head.b:skin:
/* ================================================
   CATATAN GURU IPS — V4 PREMIUM EDITION
   Design: Modern Dark Editorial
   By: Catur Pamungkas | Refactored V4
   - Font: Plus Jakarta Sans + Playfair Display
   - Lebih ringan, SEO-friendly, semua fitur aktif
================================================ */

/* ========== CSS VARIABLES ========== */
:root {
  --primary: #22d3ee;
  --primary-dark: #06b6d4;
  --secondary: #818cf8;
  --accent: #f43f5e;
  --accent-muted: rgba(244, 63, 94, 0.15);
  --gradient-primary: linear-gradient(135deg, #22d3ee 0%, #818cf8 60%, #f43f5e 100%);
  --gradient-brand: linear-gradient(135deg, #0ea5e9 0%, #6366f1 100%);
  --gradient-subtle: linear-gradient(135deg, rgba(34,211,238,0.1) 0%, rgba(129,140,248,0.1) 100%);

  --bg-primary: #060d1a;
  --bg-secondary: #0d1526;
  --bg-card: #111d33;
  --bg-card-hover: #162040;
  --bg-glass: rgba(13, 21, 38, 0.88);
  --bg-input: rgba(34, 211, 238, 0.05);

  --text-primary: #f0f6ff;
  --text-secondary: #94a3b8;
  --text-muted: #4e637a;

  --border: rgba(34, 211, 238, 0.15);
  --border-hover: rgba(34, 211, 238, 0.4);

  --shadow-card: 0 4px 24px rgba(0,0,0,0.4);
  --shadow-glow: 0 0 24px rgba(34, 211, 238, 0.2);
  --shadow-hover: 0 8px 40px rgba(0,0,0,0.5), 0 0 20px rgba(34, 211, 238, 0.15);

  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 18px;
  --radius-xl: 24px;
  --radius-full: 9999px;

  --ease: cubic-bezier(0.4, 0, 0.2, 1);
  --t-fast: 0.15s var(--ease);
  --t-normal: 0.28s var(--ease);
  --t-slow: 0.45s var(--ease);

  --header-h: 72px;
}

[data-theme="light"] {
  --bg-primary: #f0f4f8;
  --bg-secondary: #ffffff;
  --bg-card: #ffffff;
  --bg-card-hover: #f8faff;
  --bg-glass: rgba(255,255,255,0.9);
  --bg-input: rgba(14, 165, 233, 0.06);
  --text-primary: #0f172a;
  --text-secondary: #475569;
  --text-muted: #94a3b8;
  --border: rgba(14, 165, 233, 0.2);
  --border-hover: rgba(14, 165, 233, 0.5);
  --shadow-card: 0 4px 20px rgba(0,0,0,0.08);
  --shadow-hover: 0 8px 32px rgba(0,0,0,0.12), 0 0 0 1px rgba(14,165,233,0.3);
}

/* ========== RESET & BASE ========== */
*, *::before, *::after { margin:0; padding:0; box-sizing:border-box; }
html { scroll-behavior:smooth; font-size:16px; -webkit-text-size-adjust:100%; }
body {
  font-family: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, sans-serif;
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.7;
  overflow-x: hidden;
  min-height: 100vh;
}

/* Subtle ambient background — CPU-friendly single gradient, no repeating patterns */
body::before {
  content: '';
  position: fixed;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 15% 10%, rgba(34,211,238,0.06) 0%, transparent 60%),
    radial-gradient(ellipse 60% 50% at 85% 85%, rgba(129,140,248,0.07) 0%, transparent 60%);
  pointer-events: none;
  z-index: -1;
}

a { color: var(--primary); text-decoration: none; transition: color var(--t-fast); }
a:hover { color: var(--primary-dark); }
h1,h2,h3,h4,h5,h6 { font-family:'Plus Jakarta Sans',sans-serif; font-weight:700; line-height:1.25; color:var(--text-primary); }
img { max-width:100%; height:auto; }
.container { max-width:1360px; margin:0 auto; padding:0 24px; }
.text-gradient {
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* ========== READING PROGRESS ========== */
.reading-progress {
  position: fixed;
  top: 0; left: 0;
  height: 3px;
  background: var(--gradient-primary);
  z-index: 9999;
  width: 0%;
  transition: width 0.1s linear;
}

/* ========== HEADER ========== */
#site-header {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 1000;
  height: var(--header-h);
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg-glass);
  backdrop-filter: blur(20px) saturate(160%);
  -webkit-backdrop-filter: blur(20px) saturate(160%);
  border-bottom: 1px solid var(--border);
  transition: height var(--t-normal), background var(--t-normal), box-shadow var(--t-normal);
}
#site-header.scrolled {
  height: 60px;
  background: rgba(6, 13, 26, 0.97);
  box-shadow: 0 4px 24px rgba(0,0,0,0.4);
}
[data-theme="light"] #site-header.scrolled {
  background: rgba(255,255,255,0.97);
}

/* Logo */
.logo-wrapper {
  display: flex;
  align-items: center;
  gap: 12px;
  text-decoration: none;
  flex-shrink: 0;
}
.logo-icon {
  width: 44px; height: 44px;
  background: var(--gradient-brand);
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 1.2rem;
  box-shadow: 0 4px 12px rgba(6, 182, 212, 0.3);
}
.logo .brand-name {
  font-size: 1.05rem;
  font-weight: 800;
  letter-spacing: -0.3px;
  background: var(--gradient-brand);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.logo .brand-tagline {
  font-size: 0.6rem;
  font-weight: 500;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-top: 1px;
}

/* Nav */
#main-nav { display:flex; align-items:center; }
#main-nav ul { list-style:none; display:flex; gap:4px; }
#main-nav > ul > li { position:relative; }
#main-nav > ul > li > a {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 10px 16px;
  color: var(--text-secondary);
  font-weight: 600;
  font-size: 0.875rem;
  border-radius: var(--radius-md);
  transition: all var(--t-fast);
}
#main-nav > ul > li > a i:first-child { color: var(--primary); font-size:0.8rem; }
#main-nav > ul > li > a .fa-chevron-down { font-size:0.6rem; transition: transform var(--t-fast); }
#main-nav > ul > li:hover > a .fa-chevron-down { transform: rotate(180deg); }
#main-nav > ul > li > a:hover { color: var(--text-primary); background: rgba(34,211,238,0.08); }

/* Dropdown */
.dropdown {
  position: absolute;
  top: calc(100% + 10px);
  left: 50%; transform: translateX(-50%) translateY(8px);
  min-width: 280px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-card), var(--shadow-glow);
  padding: 10px;
  opacity: 0; visibility: hidden;
  transition: all var(--t-normal);
  z-index: 100;
}
#main-nav li:hover .dropdown {
  opacity: 1; visibility: visible;
  transform: translateX(-50%) translateY(0);
}
.dropdown a {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 11px 14px;
  color: var(--text-secondary);
  font-size: 0.875rem;
  font-weight: 500;
  border-radius: var(--radius-sm);
  transition: all var(--t-fast);
}
.dropdown a:hover { background: rgba(34,211,238,0.08); color: var(--primary); transform: translateX(4px); }
.dropdown a i {
  width: 34px; height: 34px;
  background: rgba(34,211,238,0.1);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; justify-content: center;
  color: var(--primary); font-size: 0.9rem;
  flex-shrink: 0;
  transition: all var(--t-fast);
}
.dropdown a:hover i { background: var(--gradient-brand); color: white; }

/* Header Actions */
.header-actions { display:flex; align-items:center; gap:8px; }
.icon-btn {
  width: 40px; height: 40px;
  border-radius: var(--radius-md);
  background: rgba(34,211,238,0.08);
  color: var(--primary);
  border: 1px solid var(--border);
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  font-size: 0.95rem;
  transition: all var(--t-fast);
  flex-shrink: 0;
}
.icon-btn:hover { background: var(--gradient-brand); color: white; border-color: transparent; box-shadow: 0 4px 12px rgba(34,211,238,0.25); transform: translateY(-1px); }
.icon-btn.primary { background: var(--gradient-brand); color: white; border: none; }
#mobile-menu-btn { display:none; }

/* ========== HERO SECTION ========== */
#hero-section {
  margin-top: calc(var(--header-h) + 32px);
  padding-bottom: 40px;
}
.hero-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 32px;
  flex-wrap: wrap; gap: 16px;
}
.hero-title-wrapper { display:flex; align-items:center; gap:14px; }
.hero-icon-large {
  width: 54px; height: 54px;
  background: var(--gradient-brand);
  border-radius: var(--radius-lg);
  display: flex; align-items: center; justify-content: center;
  color: white; font-size: 1.5rem;
  box-shadow: 0 8px 24px rgba(6,182,212,0.3);
  flex-shrink: 0;
}
.hero-title {
  font-family: 'Playfair Display', serif;
  font-size: 1.75rem;
  font-weight: 800;
  letter-spacing: -0.5px;
}
.hero-subtitle { font-size: 0.9rem; color: var(--text-muted); margin-top: 3px; }
.hero-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
}
@media (max-width:1100px) { .hero-grid { grid-template-columns: repeat(2,1fr); } }
@media (max-width:680px) { .hero-grid { grid-template-columns: 1fr; } }

.hero-card {
  position: relative;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 26px;
  display: flex; flex-direction: column; gap: 14px;
  transition: all var(--t-normal);
  overflow: hidden;
  text-decoration: none; color: inherit;
}
.hero-card::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0;
  height: 2px;
  background: var(--gradient-primary);
  transform: scaleX(0);
  transition: transform var(--t-normal);
}
.hero-card:hover {
  transform: translateY(-6px);
  box-shadow: var(--shadow-hover);
  border-color: var(--border-hover);
  background: var(--bg-card-hover);
}
.hero-card:hover::before { transform: scaleX(1); }
.hero-card-icon {
  width: 52px; height: 52px;
  background: rgba(34,211,238,0.1);
  border-radius: var(--radius-md);
  display: flex; align-items: center; justify-content: center;
  font-size: 1.5rem; color: var(--primary);
  transition: all var(--t-normal);
  flex-shrink: 0;
}
.hero-card:hover .hero-card-icon { background: var(--gradient-brand); color: white; box-shadow: 0 4px 16px rgba(6,182,212,0.3); }
.hero-card h3 { font-size: 1.15rem; font-weight: 700; }
.hero-card p { font-size: 0.875rem; color: var(--text-secondary); line-height: 1.6; }
.hero-link {
  display: inline-flex; align-items: center; gap: 8px;
  font-weight: 700; font-size: 0.85rem;
  color: var(--primary); margin-top: auto; padding-top: 6px;
}
.hero-link i { transition: transform var(--t-fast); font-size: 0.75rem; }
.hero-card:hover .hero-link i { transform: translateX(5px); }
.hero-card.featured {
  background: var(--gradient-brand);
  border: none; color: white;
}
.hero-card.featured .hero-card-icon { background: rgba(255,255,255,0.2); color: white; }
.hero-card.featured h3, .hero-card.featured p { color: white; }
.hero-card.featured .hero-link { color: rgba(255,255,255,0.9); }
.hero-card.featured:hover .hero-card-icon { background: rgba(255,255,255,0.3); }

/* ========== SECTION HEADER ========== */
.section-header { text-align: center; margin-bottom: 44px; }
.section-badge {
  display: inline-flex; align-items: center; gap: 7px;
  padding: 6px 18px;
  background: rgba(34,211,238,0.1);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  font-size: 0.75rem; font-weight: 700;
  color: var(--primary);
  text-transform: uppercase; letter-spacing: 1.2px;
  margin-bottom: 14px;
}
.section-title {
  font-family: 'Playfair Display', serif;
  font-size: 2rem; font-weight: 800;
  letter-spacing: -0.5px; margin-bottom: 10px;
}
.section-desc { font-size: 1rem; color: var(--text-secondary); max-width: 560px; margin: 0 auto; }

/* ========== CPNS SECTION ========== */
#cpns-section { padding: 56px 0; }
.skd-grid {
  display: grid;
  grid-template-columns: repeat(3,1fr);
  gap: 20px; margin-bottom: 40px;
}
@media (max-width:900px) { .skd-grid { grid-template-columns: repeat(2,1fr); } }
@media (max-width:580px) { .skd-grid { grid-template-columns: 1fr; } }

.skd-card {
  position: relative;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 30px 24px;
  text-align: center;
  transition: all var(--t-normal);
  overflow: hidden;
  display: flex; flex-direction: column;
  text-decoration: none; color: inherit;
}
.skd-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; }
.skd-card.twk::before { background: linear-gradient(90deg, #22d3ee, #a5f3fc); }
.skd-card.tiu::before { background: linear-gradient(90deg, #818cf8, #c084fc); }
.skd-card.tkp::before { background: linear-gradient(90deg, #f43f5e, #fb923c); }
.skd-card:hover { transform: translateY(-6px); box-shadow: var(--shadow-hover); border-color: var(--border-hover); }
.skd-icon {
  width: 72px; height: 72px;
  margin: 0 auto 18px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.8rem;
  flex-shrink: 0;
}
.skd-card.twk .skd-icon { background: rgba(34,211,238,0.12); color: #22d3ee; }
.skd-card.tiu .skd-icon { background: rgba(129,140,248,0.12); color: #818cf8; }
.skd-card.tkp .skd-icon { background: rgba(244,63,94,0.12); color: #f43f5e; }
.skd-card h3 { font-size: 1.3rem; font-weight: 800; margin-bottom: 4px; }
.skd-card .skd-full { font-size: 0.8rem; color: var(--text-muted); margin-bottom: 12px; text-transform: uppercase; letter-spacing: 0.5px; }
.skd-card p { font-size: 0.875rem; color: var(--text-secondary); margin-bottom: 18px; flex-grow: 1; line-height: 1.6; }
.skd-stats { display: flex; justify-content: center; gap: 20px; padding-top: 14px; border-top: 1px solid var(--border); }
.skd-stats span { font-size: 0.82rem; color: var(--text-muted); }
.skd-stats strong { color: var(--primary); font-weight: 700; }

/* ========== SPONSOR SECTION ========== */
#sponsor-section { padding: 56px 0; }
.sponsor-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 20px; }
@media (max-width:1100px) { .sponsor-grid { grid-template-columns: repeat(2,1fr); } }
@media (max-width:580px) { .sponsor-grid { grid-template-columns: 1fr; } }

.sponsor-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 26px 22px;
  text-align: center;
  transition: all var(--t-normal);
  display: flex; flex-direction: column;
  position: relative; overflow: hidden;
}
.sponsor-card:hover { transform: translateY(-4px); box-shadow: var(--shadow-hover); border-color: var(--border-hover); }
.sponsor-icon {
  width: 64px; height: 64px;
  margin: 0 auto 14px;
  background: var(--gradient-brand);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.6rem; color: white;
}
.sponsor-card h3 { font-size: 1.05rem; margin-bottom: 8px; }
.sponsor-card p { font-size: 0.85rem; color: var(--text-secondary); margin-bottom: 16px; flex-grow: 1; line-height: 1.55; }
.sponsor-cta {
  display: inline-block;
  padding: 9px 20px;
  background: rgba(34,211,238,0.1);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  color: var(--primary);
  font-size: 0.82rem; font-weight: 700;
  transition: all var(--t-fast);
}
.sponsor-cta:hover { background: var(--gradient-brand); color: white; border-color: transparent; }

/* ========== CONTENT WRAPPER ========== */
#content-wrapper {
  display: grid;
  grid-template-columns: 1fr;
  gap: 28px;
  padding: 28px 0;
}
@media (min-width:1100px) { #content-wrapper { grid-template-columns: 1fr 360px; } }

body.item-view #content-wrapper,
body.static-view #content-wrapper {
  display: block;
  max-width: 1080px;
  margin: 0 auto;
  padding: 36px 0;
}
body.item-view #sidebar,
body.static-view #sidebar { display: none !important; }

/* Post detail card lebih luas dan tanpa padding berlebih */
body.item-view .post-card {
  padding: 40px 52px;
  border-radius: var(--radius-xl);
}
body.item-view .post-title {
  font-size: 2.2rem;
  line-height: 1.25;
  margin-bottom: 16px;
}
body.item-view .post-meta {
  font-size: 0.92rem;
  margin-bottom: 24px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border);
}
body.item-view .post-body {
  font-size: 1.075rem;
  line-height: 1.9;
  max-width: 78ch;
  margin: 0 auto;
}
@media (max-width: 900px) {
  body.item-view .post-card { padding: 28px 28px; }
  body.item-view .post-title { font-size: 1.65rem; }
  body.item-view .post-body { font-size: 1rem; max-width: 100%; }
}
@media (max-width: 580px) {
  body.item-view .post-card { padding: 20px 18px; }
  body.item-view .post-title { font-size: 1.35rem; }
}

/* ========== POST CARD (ARTICLE LIST) ========== */
.post-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 28px;
  margin-bottom: 24px;
  transition: all var(--t-normal);
  position: relative;
  overflow: hidden;
}
.post-card:hover { box-shadow: var(--shadow-hover); border-color: var(--border-hover); }
.post-card::after {
  content: '';
  position: absolute; left: 0; top: 0; bottom: 0;
  width: 3px;
  background: var(--gradient-primary);
  transform: scaleY(0);
  transition: transform var(--t-normal);
  border-radius: 0 0 0 var(--radius-xl);
}
.post-card:hover::after { transform: scaleY(1); }

/* Badge/Label */
.badge {
  display: inline-flex; align-items: center; gap: 5px;
  padding: 5px 14px;
  background: rgba(34,211,238,0.1);
  color: var(--primary);
  border-radius: var(--radius-full);
  font-size: 0.72rem; font-weight: 700;
  text-transform: uppercase; letter-spacing: 0.5px;
  border: 1px solid rgba(34,211,238,0.25);
}
.badge::before { content: ''; width: 5px; height: 5px; background: var(--primary); border-radius: 50%; }

/* Post Card List (Homepage thumbnail style) */
.post-card-list { padding: 0; overflow: hidden; display: flex; flex-direction: column; }
.post-thumbnail-link {
  display: block; overflow: hidden;
  border-radius: var(--radius-xl) var(--radius-xl) 0 0;
}
.post-thumbnail {
  width: 100%; height: 220px;
  object-fit: cover; display: block;
  transition: transform 0.5s var(--ease);
  border: none; margin: 0; box-shadow: none; border-radius: 0;
}
.post-card-list:hover .post-thumbnail { transform: scale(1.03); }

/* Auto-generated thumbnail untuk post tanpa gambar */
.post-thumbnail-generated {
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  width: 100%; height: 220px;
  background: linear-gradient(135deg, #0d1526 0%, #111d33 50%, #162040 100%);
  position: relative; overflow: hidden; gap: 10px;
  border-radius: var(--radius-xl) var(--radius-xl) 0 0;
  text-decoration: none; padding: 20px;
  transition: all var(--t-normal);
}
[data-theme="light"] .post-thumbnail-generated {
  background: linear-gradient(135deg, #0f172a 0%, #1e293b 50%, #0c4a6e 100%);
}
.post-thumbnail-generated::before {
  content: '';
  position: absolute; inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 20% 20%, rgba(34,211,238,0.15) 0%, transparent 60%),
    radial-gradient(ellipse 60% 50% at 80% 80%, rgba(129,140,248,0.12) 0%, transparent 60%);
  pointer-events: none;
}
.post-thumbnail-generated::after {
  content: '';
  position: absolute;
  top: 50%; left: 50%; transform: translate(-50%, -50%);
  width: 180px; height: 180px;
  background: radial-gradient(circle, rgba(34,211,238,0.08) 0%, transparent 70%);
  border-radius: 50%;
}
.post-card-list:hover .post-thumbnail-generated {
  background: linear-gradient(135deg, #111d33 0%, #162040 50%, #1a2a50 100%);
}
.post-thumb-icon {
  font-size: 2.8rem;
  background: var(--gradient-primary);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  z-index: 1;
  filter: drop-shadow(0 0 14px rgba(34,211,238,0.5));
  order: 1;
}
.post-thumb-label {
  font-size: 0.7rem; font-weight: 700;
  letter-spacing: 0.12em; text-transform: uppercase;
  color: #22d3ee; z-index: 1;
  background: rgba(34,211,238,0.12);
  border: 1px solid rgba(34,211,238,0.35);
  padding: 3px 12px; border-radius: 999px;
  order: 0;
}
.post-thumb-title {
  font-size: 0.85rem; font-weight: 600; color: #e2e8f0;
  text-align: center; z-index: 1; line-height: 1.5;
  display: -webkit-box; -webkit-line-clamp: 2;
  -webkit-box-orient: vertical; overflow: hidden;
  max-width: 90%; order: 2;
}
@media (max-width:768px) {
  .post-thumbnail-generated { height: 180px; }
}

.post-card-content { padding: 26px 28px 28px; }
.post-title-list { font-size: 1.4rem !important; margin-top: 10px; }
.post-snippet {
  color: var(--text-secondary);
  margin-bottom: 18px; line-height: 1.7;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  font-size: 0.925rem;
}
@media (max-width:768px) {
  .post-thumbnail { height: 180px; }
  .post-card-content { padding: 18px; }
  .post-title-list { font-size: 1.2rem !important; }
}

/* Post Title + Meta */
.post-title {
  font-family: 'Playfair Display', serif;
  font-size: 1.9rem; font-weight: 800;
  margin: 14px 0 10px;
  line-height: 1.2; letter-spacing: -0.5px;
}
.post-title a { color: var(--text-primary); }
.post-title a:hover { color: var(--primary); }

.post-meta {
  display: flex; flex-wrap: wrap; gap: 18px;
  font-size: 0.82rem; color: var(--text-muted);
  margin-bottom: 22px;
  padding-bottom: 18px;
  border-bottom: 1px solid var(--border);
}
.post-meta span { display: flex; align-items: center; gap: 7px; }
.post-meta i { font-size: 0.78rem; color: var(--primary); }

/* ========== POST HERO IMAGE ========== */
.post-hero-img {
  width: 100%; margin: 28px 0 36px;
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: 0 8px 40px rgba(0,0,0,0.22);
}
.post-hero-img-el {
  width: 100%; max-height: 560px;
  object-fit: cover; display: block;
  border-radius: var(--radius-lg);
  margin: 0;
}
/* Placeholder hero untuk post tanpa gambar */
.post-hero-generated {
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  min-height: 320px; gap: 14px; padding: 40px 28px;
  background: linear-gradient(135deg, #0d1526 0%, #111d33 50%, #162040 100%);
  position: relative;
}
[data-theme="light"] .post-hero-generated {
  background: linear-gradient(135deg, #0f172a 0%, #1e293b 50%, #0c4a6e 100%);
}
.post-hero-generated::before {
  content: '';
  position: absolute; inset: 0;
  background:
    radial-gradient(ellipse 70% 60% at 15% 15%, rgba(34,211,238,0.14) 0%, transparent 60%),
    radial-gradient(ellipse 55% 50% at 85% 85%, rgba(129,140,248,0.12) 0%, transparent 60%);
  pointer-events: none;
}
.post-hero-label {
  font-size: 0.75rem; font-weight: 700;
  letter-spacing: 0.14em; text-transform: uppercase;
  color: #22d3ee; z-index: 1;
  background: rgba(34,211,238,0.12);
  border: 1px solid rgba(34,211,238,0.35);
  padding: 4px 16px; border-radius: 999px;
}
.post-hero-icon {
  font-size: 3.6rem; z-index: 1;
  background: linear-gradient(135deg, #22d3ee, #818cf8, #f43f5e);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  background-clip: text;
  filter: drop-shadow(0 0 18px rgba(34,211,238,0.45));
}
.post-hero-title {
  font-size: 1.1rem; font-weight: 700; color: #e2e8f0;
  text-align: center; z-index: 1; line-height: 1.5;
  max-width: 80%;
}
@media (max-width: 768px) {
  .post-hero-img-el { max-height: 260px; }
  .post-hero-generated { min-height: 220px; }
  .post-hero-icon { font-size: 2.8rem; }
  .post-hero-title { font-size: 0.95rem; max-width: 90%; }
}

/* Post Body */
.post-body { font-size: 1.025rem; line-height: 1.85; color: var(--text-secondary); }
.post-body p { margin-bottom: 16px; }
.post-body h2 {
  font-family: 'Playfair Display', serif;
  font-size: 1.45rem; font-weight: 700;
  margin: 32px 0 12px; color: var(--text-primary);
  padding-bottom: 8px;
  border-bottom: 2px solid var(--border);
}
.post-body h3 {
  font-size: 1.2rem; font-weight: 700;
  margin: 24px 0 10px; color: var(--text-primary);
}
.post-body h4,.post-body h5,.post-body h6 {
  font-weight: 600; margin: 18px 0 8px; color: var(--text-primary);
}
.post-body ul,.post-body ol { margin: 14px 0; padding-left: 26px; }
.post-body li { margin-bottom: 7px; color: var(--text-secondary); }
.post-body li::marker { color: var(--primary); }
.post-body img {
loading: lazy;
  max-width: 100%; height: auto;
  border-radius: var(--radius-md);
  margin: 18px auto; display: block;
  box-shadow: var(--shadow-card);
  border: 1px solid var(--border);
}
.post-body figure { margin: 22px 0; text-align: center; }
.post-body figcaption { font-size: 0.82rem; color: var(--text-muted); margin-top: 6px; font-style: italic; }
.post-body a { color: var(--primary); border-bottom: 1px dotted var(--primary); }
.post-body a:hover { color: var(--primary-dark); border-bottom-style: solid; }
.post-body blockquote {
  margin: 22px 0; padding: 18px 22px;
  background: rgba(34,211,238,0.05);
  border-left: 3px solid var(--primary);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  font-style: italic; color: var(--text-secondary);
}
.post-body blockquote p { margin-bottom: 0; }
.post-body pre {
  background: var(--bg-secondary);
  padding: 18px; border-radius: var(--radius-md);
  overflow-x: auto; margin: 14px 0;
  border: 1px solid var(--border);
  font-size: 0.9rem;
}
.post-body code {
  background: rgba(34,211,238,0.1);
  padding: 2px 7px; border-radius: 4px;
  font-size: 0.9em;
  font-family: 'Fira Code', 'Courier New', monospace;
}
.post-body pre code { background: transparent; padding: 0; }
.post-body hr { border: none; height: 2px; background: var(--gradient-primary); margin: 28px 0; opacity: 0.3; border-radius: 2px; }
.post-body table { width: 100%; border-collapse: collapse; margin: 22px 0; font-size: 0.92rem; overflow-x: auto; display: block; border: 1px solid var(--border); border-radius: var(--radius-md); }
.post-body table thead { background: rgba(34,211,238,0.1); }
.post-body table th { padding: 12px 14px; text-align: left; font-weight: 700; color: var(--primary); border-bottom: 2px solid var(--border); white-space: nowrap; }
.post-body table td { padding: 10px 14px; border-bottom: 1px solid var(--border); color: var(--text-secondary); vertical-align: top; }
.post-body table tr:last-child td { border-bottom: none; }
.post-body table tr:hover td { background: rgba(34,211,238,0.03); }
.post-body iframe,.post-body embed,.post-body object { max-width: 100%; }
.post-body .separator { text-align: center; margin: 18px 0; }

/* ========== PAGER ========== */
.blog-pager {
  display: flex; justify-content: center; align-items: center;
  gap: 14px; padding: 28px 0; flex-wrap: wrap;
}
.blog-pager a {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 12px 24px;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  color: var(--text-secondary);
  font-weight: 600; font-size: 0.875rem;
  transition: all var(--t-fast);
}
.blog-pager a:hover { background: var(--gradient-brand); color: white; border-color: transparent; box-shadow: 0 4px 16px rgba(6,182,212,0.25); }
.home-link { background: rgba(34,211,238,0.08); color: var(--primary); }

/* ========== SIDEBAR ========== */
#sidebar { display: flex; flex-direction: column; gap: 20px; }
.sidebar-widget {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-xl);
  padding: 22px;
  transition: box-shadow var(--t-normal);
  position: relative;
}
.sidebar-widget::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0;
  height: 2px;
  background: var(--gradient-brand);
  border-radius: var(--radius-xl) var(--radius-xl) 0 0;
}
.sidebar-widget:hover { box-shadow: var(--shadow-card); }

.widget-title {
  font-size: 0.72rem; font-weight: 800;
  text-transform: uppercase; letter-spacing: 1.5px;
  color: var(--primary);
  margin-bottom: 18px; padding-bottom: 10px;
  border-bottom: 1px solid var(--border);
  display: flex; align-items: center; gap: 8px;
}

/* Profile Widget */
.profile-widget { text-align: center; padding: 26px 22px; }
.profile-avatar-wrapper { position: relative; width: 100px; height: 100px; margin: 0 auto 14px; }
.profile-avatar {
  width: 100px; height: 100px;
  border-radius: 50%;
  border: 3px solid var(--primary);
  box-shadow: 0 0 20px rgba(34,211,238,0.2);
  display: block; object-fit: cover;
  transition: transform var(--t-normal);
}
.profile-avatar-wrapper::after {
  content: '';
  position: absolute; inset: -5px;
  border: 2px dashed rgba(34,211,238,0.3);
  border-radius: 50%;
  animation: spin 20s linear infinite;
  pointer-events: none;
}
@keyframes spin { 100% { transform: rotate(360deg); } }
.profile-avatar:hover { transform: scale(1.04); }
.profile-name { font-size: 1.1rem; font-weight: 700; margin-bottom: 6px; }
.profile-badge {
  display: inline-block;
  padding: 5px 14px;
  background: var(--gradient-brand);
  color: white; border-radius: var(--radius-full);
  font-size: 0.72rem; font-weight: 700;
  margin-bottom: 10px;
}
.profile-bio { font-size: 0.85rem; color: var(--text-secondary); line-height: 1.55; margin-bottom: 14px; }

/* Social Links */
.social-links {
  display: flex; justify-content: center; flex-wrap: wrap; gap: 8px;
  padding-top: 14px; border-top: 1px solid var(--border);
}
.social-link {
  width: 38px; height: 38px;
  border-radius: var(--radius-md);
  background: rgba(34,211,238,0.08);
  border: 1px solid var(--border);
  display: flex; align-items: center; justify-content: center;
  color: var(--primary); font-size: 1rem;
  transition: all var(--t-fast);
}
.social-link:hover { background: var(--gradient-brand); color: white; border-color: transparent; transform: translateY(-2px) scale(1.08); box-shadow: 0 4px 12px rgba(34,211,238,0.25); }
.social-link.facebook:hover { background: #1877f2; box-shadow: 0 4px 12px rgba(24,119,242,0.3); }
.social-link.instagram:hover { background: linear-gradient(135deg, #f09433, #e6683c, #dc2743, #bc1888); box-shadow: 0 4px 12px rgba(225,48,108,0.3); }
.social-link.youtube:hover { background: #ff0000; box-shadow: 0 4px 12px rgba(255,0,0,0.3); }
.social-link.whatsapp:hover { background: #25d366; box-shadow: 0 4px 12px rgba(37,211,102,0.3); }
.social-link.threads:hover { background: #000; }

/* Stats Grid */
.stats-grid { display: grid; grid-template-columns: repeat(2,1fr); gap: 12px; }
.stat-item {
  text-align: center; padding: 16px 10px;
  background: rgba(34,211,238,0.05);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  transition: all var(--t-fast);
}
.stat-item:hover { background: rgba(34,211,238,0.1); border-color: var(--border-hover); }
.stat-number {
  font-size: 1.5rem; font-weight: 800;
  background: var(--gradient-primary);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
  display: block; line-height: 1.2;
}
.stat-label { font-size: 0.7rem; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; margin-top: 2px; }

/* Quick Links */
.quick-links { list-style: none; }
.quick-links li { margin-bottom: 8px; }
.quick-links a {
  display: flex; align-items: center; gap: 10px;
  padding: 10px 14px;
  background: rgba(34,211,238,0.04);
  border: 1px solid transparent;
  border-radius: var(--radius-md);
  color: var(--text-secondary);
  font-size: 0.875rem;
  transition: all var(--t-fast);
}
.quick-links a:hover { background: rgba(34,211,238,0.08); border-color: var(--border-hover); color: var(--primary); transform: translateX(4px); }
.quick-links a i {
  width: 30px; height: 30px;
  background: rgba(34,211,238,0.1);
  border-radius: var(--radius-sm);
  display: flex; align-items: center; justify-content: center;
  color: var(--primary); font-size: 0.85rem;
  flex-shrink: 0;
  transition: all var(--t-fast);
}
.quick-links a:hover i { background: var(--gradient-brand); color: white; }

/* Tags Cloud */
.tags-cloud { display: flex; flex-wrap: wrap; gap: 8px; }
.tag-link {
  padding: 5px 13px;
  background: rgba(34,211,238,0.08);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  font-size: 0.78rem; color: var(--text-secondary);
  transition: all var(--t-fast);
}
.tag-link:hover { background: var(--gradient-brand); color: white; border-color: transparent; }

/* ========== SHARE BUTTONS ========== */
.share-container {
  background: var(--bg-card);
  padding: 22px; margin: 28px 0;
  border-radius: var(--radius-lg);
  border: 1px solid var(--border);
  border-left: 4px solid var(--primary);
}
.share-container .share-title { font-weight: 700; color: var(--text-primary); font-size: 0.925rem; margin-bottom: 14px; }
.social-flex { display: flex; flex-wrap: wrap; gap: 10px; }
.btn-share {
  display: inline-flex; align-items: center; justify-content: center;
  padding: 10px 18px; border-radius: var(--radius-full);
  font-size: 0.85rem; font-weight: 700;
  text-decoration: none !important; color: white !important;
  transition: all var(--t-fast); cursor: pointer; border: none; gap: 7px;
}
.btn-share:hover { transform: translateY(-2px); box-shadow: 0 6px 16px rgba(0,0,0,0.25); filter: brightness(1.1); }
.btn-share.wa { background: #25D366; }
.btn-share.fb { background: #4267B2; }
.btn-share.x-twitter { background: #000; }
.btn-share.linkedin { background: #0077b5; }
.btn-share.copy-link { background: #334155; }
.btn-share.copy-success { background: #10b981 !important; }
@media (max-width:580px) { .btn-share { padding: 9px 14px; font-size: 0.8rem; } }

/* ========== COMMENTS ========== */
.comments-section { margin-top: 36px; padding-top: 28px; border-top: 1px solid var(--border); }
.comments-section-title {
  font-size: 1.2rem; margin-bottom: 20px;
  display: flex; align-items: center; gap: 10px;
}
.comments-section-title i { color: var(--primary); }
.comments-info {
  padding: 13px 18px;
  background: rgba(34,211,238,0.06);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  margin-bottom: 20px;
  font-size: 0.875rem; color: var(--text-secondary);
}
.comments-info i { color: var(--primary); margin-right: 6px; }

#comments { clear: both; }
.comments {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 22px; margin-top: 18px;
}
.comments .comments-content { margin-bottom: 22px; }
.comments h3.title {
  font-size: 1.05rem; margin-bottom: 18px;
  color: var(--text-primary);
  padding-bottom: 10px; border-bottom: 1px solid var(--border);
}
.comments .comment { margin-bottom: 22px; clear: both; overflow: hidden; }
.comments .comment .comment { margin-left: 55px; margin-top: 18px; padding-left: 18px; border-left: 2px solid var(--border); }
.comments .comment-block {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 18px; margin-left: 50px; margin-bottom: 14px;
  position: relative;
}
.comments .comment-author { font-weight: 700; margin-bottom: 8px; font-size: 0.9rem; }
.comments .comment-author a { color: var(--primary); }
.comments .comment-body { color: var(--text-secondary); font-size: 0.9rem; line-height: 1.6; }
.comments .comment-body.deleted { color: var(--text-muted); font-style: italic; }
.comments .comment-footer { margin-top: 10px; font-size: 0.78rem; }
.comments .comment-timestamp a { color: var(--text-muted); }
.comments .comment-timestamp a:hover { color: var(--primary); }
.comments .avatar-image-container { float: left; margin-right: 12px; }
.comments .avatar-image-container img { width: 42px; height: 42px; border-radius: 50%; border: 2px solid var(--border); }
.comments .continue a,.comments .loadmore a {
  display: inline-flex; align-items: center; gap: 7px;
  padding: 10px 20px;
  background: rgba(34,211,238,0.08);
  border: 1px solid var(--border);
  border-radius: var(--radius-full);
  color: var(--primary); font-size: 0.82rem; font-weight: 600;
  transition: all var(--t-fast);
}
.comments .continue a:hover,.comments .loadmore a:hover { background: var(--gradient-brand); color: white; border-color: transparent; }
.comments .loadmore { text-align: center; margin-top: 20px; }

.comment-form {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 22px; margin-top: 22px;
}
.comment-form h4 { font-size: 0.95rem; margin-bottom: 14px; color: var(--primary); }
.comment-form iframe { width: 100%; min-height: 280px; border: none; border-radius: var(--radius-md); background: transparent; }
.item-control { display: inline-block; margin-left: 10px; }
.comment-delete { opacity: 0.5; transition: opacity var(--t-fast); }
.comment-delete:hover { opacity: 1; }
.comment-delete img { width: 13px; height: 13px; }
.no-comments { text-align: center; padding: 36px 20px; color: var(--text-muted); }
.no-comments i { font-size: 2.5rem; margin-bottom: 12px; opacity: 0.3; display: block; }

/* ========== FOOTER ========== */
#site-footer {
  background: var(--bg-secondary);
  border-top: 1px solid var(--border);
  padding: 72px 0 28px;
  margin-top: 56px;
  position: relative;
}
#site-footer::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: var(--gradient-primary); }
.footer-grid {
  display: grid;
  grid-template-columns: 2fr repeat(3,1fr);
  gap: 44px; margin-bottom: 44px;
}
@media (max-width:1100px) { .footer-grid { grid-template-columns: 1fr 1fr; gap: 28px; } }
@media (max-width:580px) { .footer-grid { grid-template-columns: 1fr; } }
.footer-brand h3 {
  font-family: 'Playfair Display', serif;
  font-size: 1.3rem; margin-bottom: 12px;
}
.footer-brand p { font-size: 0.875rem; color: var(--text-secondary); line-height: 1.65; margin-bottom: 18px; }
.footer-social { display: flex; gap: 10px; flex-wrap: wrap; }
.footer-social a {
  width: 40px; height: 40px;
  background: rgba(34,211,238,0.08);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  display: flex; align-items: center; justify-content: center;
  color: var(--primary); font-size: 1rem;
  transition: all var(--t-fast);
}
.footer-social a:hover { background: var(--gradient-brand); color: white; border-color: transparent; transform: translateY(-2px); }
.footer-links h4 {
  font-size: 0.72rem; font-weight: 800;
  text-transform: uppercase; letter-spacing: 1.2px;
  color: var(--primary); margin-bottom: 18px;
}
.footer-links ul { list-style: none; }
.footer-links li { margin-bottom: 10px; }
.footer-links a { color: var(--text-secondary); font-size: 0.875rem; display: flex; align-items: center; gap: 7px; transition: all var(--t-fast); }
.footer-links a:hover { color: var(--primary); transform: translateX(3px); }
.footer-links a i { font-size: 0.65rem; opacity: 0; transition: opacity var(--t-fast); }
.footer-links a:hover i { opacity: 1; }
.copyright {
  text-align: center;
  padding-top: 28px; border-top: 1px solid var(--border);
  font-size: 0.82rem; color: var(--text-muted);
}
.copyright i.fa-heart { color: #f43f5e; animation: heartbeat 1.5s ease infinite; }
@keyframes heartbeat { 0%,100% { transform: scale(1); } 50% { transform: scale(1.2); } }

/* ========== SEARCH OVERLAY ========== */
#search-overlay {
  position: fixed; inset: 0;
  background: rgba(6,13,26,0.92);
  backdrop-filter: blur(12px);
  z-index: 2000;
  display: none; align-items: flex-start; justify-content: center;
  padding-top: 120px;
  opacity: 0; transition: opacity var(--t-normal);
}
#search-overlay.active { opacity: 1; }
#search-box {
  background: var(--bg-card);
  padding: 32px;
  border-radius: var(--radius-xl);
  width: 92%; max-width: 580px;
  border: 1px solid var(--border);
  box-shadow: var(--shadow-card);
  position: relative;
  transform: translateY(16px);
  transition: transform var(--t-normal);
}
#search-overlay.active #search-box { transform: translateY(0); }
#search-close {
  position: absolute; top: 16px; right: 20px;
  font-size: 1.3rem; cursor: pointer;
  color: var(--text-muted); transition: all var(--t-fast);
}
#search-close:hover { color: var(--primary); transform: rotate(90deg); }
#search-box h3 { font-size: 1.2rem; margin-bottom: 22px; display: flex; align-items: center; gap: 10px; }
#search-box h3 i { color: var(--primary); }
.filter-btns { display: flex; gap: 8px; margin-bottom: 20px; flex-wrap: wrap; }
.filter-btn {
  padding: 8px 16px;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--text-secondary);
  border-radius: var(--radius-full);
  cursor: pointer; font-size: 0.82rem; font-weight: 600;
  transition: all var(--t-fast);
}
.filter-btn:hover { border-color: var(--primary); color: var(--primary); }
.filter-btn.active { background: var(--gradient-brand); color: white; border-color: transparent; }
.search-input-box { display: flex; gap: 10px; }
.search-input-box input {
  flex: 1; padding: 14px 18px;
  border: 2px solid var(--border);
  border-radius: var(--radius-md);
  background: var(--bg-input);
  color: var(--text-primary); font-size: 0.95rem;
  outline: none; transition: border-color var(--t-fast);
  font-family: 'Plus Jakarta Sans', sans-serif;
}
.search-input-box input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(34,211,238,0.1); }
.search-input-box input::placeholder { color: var(--text-muted); }

/* ========== BACK TO TOP ========== */
#back-top {
  position: fixed; bottom: 28px; right: 28px;
  width: 50px; height: 50px;
  background: var(--gradient-brand);
  color: white; border-radius: 50%;
  display: none; align-items: center; justify-content: center;
  cursor: pointer; z-index: 999;
  box-shadow: 0 8px 24px rgba(6,182,212,0.35);
  transition: all var(--t-normal);
  font-size: 1.1rem;
}
#back-top:hover { transform: translateY(-3px) scale(1.08); box-shadow: 0 12px 32px rgba(6,182,212,0.45); }

/* ========== ANIMATIONS ========== */
@keyframes fadeUp { from { opacity:0; transform: translateY(18px); } to { opacity:1; transform: translateY(0); } }
@keyframes float { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-8px); } }
.animate-fade-in { animation: fadeUp 0.5s var(--ease) forwards; }

/* ========== MOBILE RESPONSIVE ========== */
@media (max-width:1100px) {
  #mobile-menu-btn { display: flex; }
  #main-nav {
    position: fixed;
    top: var(--header-h); left: 0;
    width: 100%; height: calc(100vh - var(--header-h));
    background: var(--bg-secondary);
    flex-direction: column; align-items: flex-start;
    padding: 20px;
    transform: translateX(-100%);
    transition: transform var(--t-normal);
    overflow-y: auto;
    border-top: 1px solid var(--border);
  }
  #main-nav.active { transform: translateX(0); }
  #main-nav ul { flex-direction: column; width: 100%; gap: 8px; }
  #main-nav li { width: 100%; }
  #main-nav > ul > li > a {
    justify-content: space-between; padding: 14px 18px;
    background: rgba(34,211,238,0.05);
    border: 1px solid var(--border);
  }
  .dropdown { position: static; opacity: 1; visibility: visible; transform: none; box-shadow: none; border: none; background: transparent; padding: 8px 0 8px 16px; display: none; margin: 0; }
  .dropdown.show { display: block; }
  .dropdown a { background: rgba(34,211,238,0.04); margin-bottom: 6px; border: 1px solid var(--border); border-radius: var(--radius-md); }
}

@media (max-width:768px) {
  .container { padding: 0 14px; }
  #site-header { padding: 0 14px; }
  .logo .brand-tagline { display: none; }
  #hero-section { margin-top: calc(var(--header-h) + 20px); padding-bottom: 28px; }
  .hero-title { font-size: 1.45rem; }
  .section-title { font-size: 1.6rem; }
  .post-card { padding: 20px; }
  .post-title { font-size: 1.5rem; }
  #back-top { bottom: 18px; right: 18px; width: 44px; height: 44px; }
  .comments .comment-block { margin-left: 44px; }
  .comments .comment .comment { margin-left: 36px; }
}

/* ========== PRINT ========== */
@media print {
  #site-header,#sidebar,#site-footer,#back-top,#search-overlay,#hero-section,#cpns-section,#sponsor-section { display: none !important; }
  body { background: white; color: #111; }
  .post-card { box-shadow: none; border: 1px solid #ddd; background: white; }
}

