body.script:
//
(function() {
  'use strict';

  // Reading progress bar
  var progressBar = document.createElement('div');
  progressBar.className = 'reading-progress';
  document.body.prepend(progressBar);

  // Header scroll
  var header = document.getElementById('site-header');
  var backTop = document.getElementById('back-top');
  window.addEventListener('scroll', function() {
    var y = window.scrollY;
    if (header) header.classList.toggle('scrolled', y > 50);
    if (backTop) backTop.style.display = y > 400 ? 'flex' : 'none';
    // Progress bar
    var docEl = document.documentElement;
    var sh = docEl.scrollHeight - docEl.clientHeight;
    progressBar.style.width = (sh > 0 ? Math.min((y / sh) * 100, 100) : 0) + '%';
  }, { passive: true });

  // Theme toggle (localStorage dengan try-catch)
  var themeToggle = document.getElementById('theme-toggle');
  if (themeToggle) {
    var savedTheme = null;
    try { savedTheme = localStorage.getItem('theme'); } catch(e) {}
    if (savedTheme === 'light') {
      document.documentElement.setAttribute('data-theme', 'light');
      themeToggle.innerHTML = '<i class="fas fa-sun"></i>';
    }
    themeToggle.addEventListener('click', function() {
      var isLight = document.documentElement.getAttribute('data-theme') === 'light';
      var next = isLight ? 'dark' : 'light';
      document.documentElement.setAttribute('data-theme', next);
      try { localStorage.setItem('theme', next); } catch(e) {}
      themeToggle.innerHTML = next === 'light' ? '<i class="fas fa-sun"></i>' : '<i class="fas fa-moon"></i>';
    });
  }

  // Search overlay
  var overlay = document.getElementById('search-overlay');
  var searchInput = document.getElementById('search-input');
  function openSearch() {
    if (!overlay) return;
    overlay.style.display = 'flex';
    requestAnimationFrame(function() { overlay.classList.add('active'); });
    if (searchInput) setTimeout(function() { searchInput.focus(); }, 120);
  }
  function closeSearch() {
    if (!overlay) return;
    overlay.classList.remove('active');
    setTimeout(function() { overlay.style.display = 'none'; }, 280);
  }
  var st = document.getElementById('search-toggle');
  var sc = document.getElementById('search-close');
  if (st) st.addEventListener('click', openSearch);
  if (sc) sc.addEventListener('click', closeSearch);
  if (overlay) overlay.addEventListener('click', function(e) { if (e.target === overlay) closeSearch(); });

  // Filter buttons
  var filterBtns = document.querySelectorAll('.filter-btn');
  filterBtns.forEach(function(btn) {
    btn.addEventListener('click', function() {
      filterBtns.forEach(function(b) { b.classList.remove('active'); });
      this.classList.add('active');
    });
  });

  // Mobile menu
  var mobileBtn = document.getElementById('mobile-menu-btn');
  var mainNav = document.getElementById('main-nav');
  if (mobileBtn && mainNav) {
    mobileBtn.addEventListener('click', function() {
      var open = mainNav.classList.toggle('active');
      var icon = mobileBtn.querySelector('i');
      if (icon) { icon.classList.toggle('fa-bars', !open); icon.classList.toggle('fa-times', open); }
    });
  }

  // Mobile dropdown toggles
  document.querySelectorAll('.has-dropdown').forEach(function(toggle) {
    toggle.addEventListener('click', function(e) {
      if (window.innerWidth <= 1100) {
        e.preventDefault();
        var dd = toggle.nextElementSibling;
        if (dd && dd.classList.contains('dropdown')) {
          var shown = dd.classList.toggle('show');
          var chev = toggle.querySelector('.fa-chevron-down');
          if (chev) chev.style.transform = shown ? 'rotate(180deg)' : '';
        }
      }
    });
  });

  // Back to top
  if (backTop) {
    backTop.addEventListener('click', function() { window.scrollTo({ top: 0, behavior: 'smooth' }); });
    backTop.addEventListener('keydown', function(e) { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); window.scrollTo({ top: 0, behavior: 'smooth' }); } });
  }

  // Keyboard shortcuts
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
      if (overlay && overlay.classList.contains('active')) closeSearch();
      if (mainNav && mainNav.classList.contains('active')) {
        mainNav.classList.remove('active');
        if (mobileBtn) {
          var icon = mobileBtn.querySelector('i');
          if (icon) { icon.classList.add('fa-bars'); icon.classList.remove('fa-times'); }
        }
      }
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'k') { e.preventDefault(); openSearch(); }
  });

  // Scroll-triggered animations
  if ('IntersectionObserver' in window) {
    var io = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          entry.target.style.opacity = '1';
          entry.target.style.transform = 'translateY(0)';
          io.unobserve(entry.target);
        }
      });
    }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' });

    function initAnim() {
      document.querySelectorAll('.post-card, .hero-card, .sidebar-widget, .skd-card, .sponsor-card').forEach(function(el, i) {
        el.style.opacity = '0';
        el.style.transform = 'translateY(16px)';
        el.style.transition = 'opacity 0.5s ease ' + (i * 0.07) + 's, transform 0.5s ease ' + (i * 0.07) + 's';
        io.observe(el);
      });
    }
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', initAnim);
    } else { initAnim(); }
  }
})();

// Copy to clipboard
function copyToClipboard() {
  var url = window.location.href;
  var titleEl = document.querySelector('.post-title');
  var title = titleEl ? titleEl.textContent.trim() : document.title;
  var text = title + ' - ' + url;
  function success() {
    var btn = document.getElementById('btn-copy');
    var ct = document.getElementById('copy-text');
    var ci = document.getElementById('copy-icon');
    if (!btn) return;
    btn.classList.add('copy-success');
    if (ct) ct.textContent = 'Tersalin!';
    if (ci) ci.textContent = '✓';
    setTimeout(function() {
      btn.classList.remove('copy-success');
      if (ct) ct.textContent = 'Salin Tautan';
      if (ci) ci.textContent = '🔗';
    }, 2500);
  }
  if (navigator.clipboard) {
    navigator.clipboard.writeText(text).then(success).catch(function() { fallback(text); });
  } else { fallback(text); }
}
function fallback(text) {
  var ta = document.createElement('textarea');
  ta.value = text;
  ta.style.cssText = 'position:fixed;left:-9999px;top:-9999px;';
  document.body.appendChild(ta);
  ta.focus(); ta.select();
  try { document.execCommand('copy'); var btn = document.getElementById('btn-copy'); if (btn) { var ct = btn.querySelector('#copy-text'); if (ct) ct.textContent = 'Tersalin!'; } }
  catch(e) { alert('Salin URL: ' + window.location.href); }
  document.body.removeChild(ta);
}
